// v1.7：批次 AI + rule-based fallback + 檔名唯一性檢查 + PDF 內容感知

const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const CHUNK_SIZE = 5;
const INTER_CHUNK_DELAY = 7000;
const RETRY_429_WAIT = 60000;

const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const items = $input.all();
const allReadItems = $('Read 所有檔案').all();

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
function cleanLeadingDigits(name) {
  const noExt = name.replace(/\.[^.]+$/, '');
  const cleaned = noExt.replace(/^[\s\-_.()【】]+/, '').trim();
  // 保留前綴的數字編號（01/02/03）以避免命名衝突
  return cleaned || noExt;
}
function filterPrintable(text) {
  if (!text || typeof text !== 'string') return '';
  const printableMatches = text.match(/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffefa-zA-Z0-9\s.,!?;:()\[\]{}\-+="'\/_*&%$#@~|<>]/g);
  const ratio = printableMatches ? printableMatches.length / text.length : 0;
  return ratio > 0.7 ? text.substring(0, 800) : '';
}

// Rule-based 檔名分類
function classifyByFilename(name, ext) {
  const n = name.toLowerCase();
  const e = (ext || '').toLowerCase();

  if (['jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'svg', 'bmp', 'tiff'].includes(e)) {
    return { category: 'images', semanticType: '圖片' };
  }
  if (['ppt', 'pptx', 'key'].includes(e) || /簡報|投影片|提案|pitch|proposal|kickoff|deck/i.test(n)) {
    return { category: 'presentations', semanticType: '簡報' };
  }
  if (/合約|協議|nda|授權書|同意書|條款/i.test(n)) {
    return { category: 'contracts', semanticType: '合約' };
  }
  if (/發票|收據|報價|估價|帳單|對帳|訂單|invoice|quote/i.test(n)) {
    return { category: 'invoices', semanticType: '報價' };
  }
  if (/會議|紀錄|逐字稿|memo|minutes|meeting/i.test(n)) {
    return { category: 'docs', semanticType: '紀錄' };
  }
  if (/提示詞|prompt|教材|講義|手冊|教學|課程/i.test(n)) {
    return { category: 'docs', semanticType: '教材' };
  }
  if (/規格|spec|brief|需求/i.test(n)) {
    return { category: 'docs', semanticType: '規格' };
  }
  if (/報告|report|分析|analysis/i.test(n)) {
    return { category: 'docs', semanticType: '報告' };
  }
  return null;  // 沒命中 — 讓 caller 決定要 fallback to content scan or 'docs/文件'
}

// PDF 內容感知 rule-based — 掃文字找關鍵字
function classifyByContent(text) {
  if (!text || text.length < 30) return null;
  const t = text.substring(0, 1500).toLowerCase();
  if (/合約|協議|nda|授權書|同意書|條款|甲方.*乙方|nondisclosure/i.test(t)) {
    return { category: 'contracts', semanticType: '合約' };
  }
  if (/發票|收據|報價|估價|帳單|對帳|金額.*nt\$|invoice|quote|稅金/i.test(t)) {
    return { category: 'invoices', semanticType: '報價' };
  }
  if (/簡報|投影片|提案/i.test(t)) {
    return { category: 'presentations', semanticType: '簡報' };
  }
  if (/會議|紀錄|memo|minutes|出席|議題|待辦/i.test(t)) {
    return { category: 'docs', semanticType: '紀錄' };
  }
  if (/提示詞|prompt engineering|教材|講義|教學|課程/i.test(t)) {
    return { category: 'docs', semanticType: '教材' };
  }
  return null;
}

function smartFallback(originalName, fileExt, usableText) {
  // 第一層：檔名規則
  const byName = classifyByFilename(originalName, fileExt);
  if (byName) return byName;
  // 第二層：內容規則（給 PDF 用 — 文字夠多時）
  const byContent = classifyByContent(usableText);
  if (byContent) return byContent;
  // 兜底
  return { category: 'docs', semanticType: '文件' };
}

const CATEGORIES = ['contracts','invoices','presentations','docs','images','others'];
const imgExts = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'svg', 'bmp', 'tiff'];

// Phase 1：整理 + 圖片快速分類
const processed = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binFileName = item.binary?.data?.fileName;
  const readItem = allReadItems.find(r => r?.json?.fileName === binFileName) || allReadItems[i];
  if (!readItem?.binary?.data) continue;

  const originalName = readItem.json.fileName || ('unknown-' + i);
  const fileExt = (readItem.json.fileExtension || '').toLowerCase();
  const rawText = item.json.text ?? item.json.data ?? '';
  const usableText = filterPrintable(rawText);

  const base = {
    idx: i, originalName, fileExt, usableText, binary: readItem.binary,
    category: null, newName: null, aiUsed: false, aiError: null
  };

  if (imgExts.includes(fileExt)) {
    base.category = 'images';
    base.newName = today + '_圖片_' + cleanLeadingDigits(originalName);
  }

  processed.push(base);
}

// Phase 2：批次 AI 呼叫
const needsAI = processed.filter(p => !p.category);
const chunks = [];
for (let i = 0; i < needsAI.length; i += CHUNK_SIZE) chunks.push(needsAI.slice(i, i + CHUNK_SIZE));

const t0 = Date.now();
const batchInfo = {
  inputCount: items.length,
  outputCount: 0,
  dedupCount: 0,
  chunks: chunks.length,
  aiCalls: 0,
  totalMs: 0,
  batchErrors: [],
  aiSucceeded: 0,
  ruleFallback: 0
};

async function callGeminiBatch(chunk) {
  const filesPart = chunk.map((f, idx) => {
    const docxHint = ['docx', 'xlsx', 'pptx'].includes(f.fileExt) ? '\n注意：Office 檔（' + f.fileExt + '）無法擷取內文，請用檔名分類' : '';
    const contentPart = f.usableText ? '\n內容摘要：' + f.usableText : '\n（無法擷取內文，憑檔名分類）';
    return '<檔案 ' + (idx + 1) + '>\n檔名：' + f.originalName + '\n副檔名：' + f.fileExt + docxHint + contentPart + '\n</檔案 ' + (idx + 1) + '>';
  }).join('\n\n');

  const prompt = '你是檔案歸檔助手。對下面 ' + chunk.length + ' 份檔案分類成 6 類之一，並取語意化檔名。\n\n' +
    '**類別定義**（看不出明確類型時優先選 docs；only fallback 到 others 在真的什麼都不像）：\n' +
    '- contracts：合約 / 協議 / NDA / 條款 / 授權書\n' +
    '- invoices：發票 / 收據 / 報價單 / 估價單 / 帳單\n' +
    '- presentations：簡報 / 投影片 / 提案 / pitch deck\n' +
    '- docs：所有文字內容文件（手冊 / 說明書 / 筆記 / 會議記錄 / 課程教材 / 教學講義 / 報告 / 任何 .txt/.md/.docx）\n' +
    '- images：圖片 / 截圖 / 設計稿\n' +
    '- others：真的什麼都不像時才選\n\n' +
    '**重要：保留檔名中的數字編號**\n' +
    '如果檔名有 01/02/03 等編號，新檔名必須保留該編號以避免衝突。例：\n' +
    '- 中小企業AI實務01.pptx → 20260506_簡報_中小企業AI實務01（保留 01）\n' +
    '- 中小企業AI實務02.pptx → 20260506_簡報_中小企業AI實務02（保留 02）\n' +
    '- 01提示詞基礎.docx → 20260506_教材_提示詞基礎（前置編號可移除，因檔名其餘部分已唯一）\n\n' +
    '**範例**：\n' +
    '- 合約_NDA_客戶A.pdf → {"category":"contracts","newName":"' + today + '_合約_客戶A NDA"}\n' +
    '- Q3-報價單.pdf → {"category":"invoices","newName":"' + today + '_報價_Q3"}\n' +
    '- 客戶提案-v1.pptx → {"category":"presentations","newName":"' + today + '_簡報_客戶提案v1"}\n' +
    '- 中小企業AI實務01.pptx → {"category":"presentations","newName":"' + today + '_簡報_中小企業AI實務01"}\n' +
    '- 中小企業AI實務02.pptx → {"category":"presentations","newName":"' + today + '_簡報_中小企業AI實務02"}\n' +
    '- 虛擬會議逐字稿.docx → {"category":"docs","newName":"' + today + '_紀錄_虛擬會議逐字稿"}\n\n' +
    '**輸出規則**：嚴格只回 JSON array，array 順序與輸入檔案順序一致，array 長度必須是 ' + chunk.length + '。\n' +
    '不要 markdown 包裹。\n\n' +
    '格式：[{"category":"xxx","newName":"' + today + '_類型_關鍵字"}, ...]\n\n' +
    filesPart;

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
    headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 1500, thinkingConfig: { thinkingBudget: 0 } }
    },
    json: true,
    timeout: 60000
  });
  const aiResp = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = aiResp.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (!m) throw new Error('no JSON array in AI response: ' + cleaned.substring(0, 200));
  const arr = JSON.parse(m[0]);
  if (!Array.isArray(arr)) throw new Error('AI response is not an array');
  return arr;
}

for (let cIdx = 0; cIdx < chunks.length; cIdx++) {
  if (cIdx > 0) await sleep(INTER_CHUNK_DELAY);

  const chunk = chunks[cIdx];
  let arr = null;
  let lastError = null;
  for (let attempt = 0; attempt < 2; attempt++) {
    batchInfo.aiCalls++;
    try {
      arr = await callGeminiBatch(chunk);
      lastError = null;
      break;
    } catch (err) {
      lastError = err.message || String(err);
      if (lastError.includes('429') && attempt === 0) {
        await sleep(RETRY_429_WAIT);
        continue;
      }
      break;
    }
  }

  if (lastError) batchInfo.batchErrors.push('chunk ' + cIdx + ': ' + lastError.substring(0, 100));

  for (let j = 0; j < chunk.length; j++) {
    const f = chunk[j];
    const r = arr && arr[j] ? arr[j] : null;
    if (r && CATEGORIES.includes(r.category)) {
      f.category = r.category;
      f.newName = r.newName || (today + '_' + cleanLeadingDigits(f.originalName));
      f.aiUsed = true;
      batchInfo.aiSucceeded++;
    } else {
      // AI 失敗 → smart rule-based fallback（檔名規則 + 內容規則 + 兜底）
      f.aiError = lastError || 'AI result missing or invalid for index ' + j;
      const ruleResult = smartFallback(f.originalName, f.fileExt, f.usableText);
      f.category = ruleResult.category;
      f.newName = today + '_' + ruleResult.semanticType + '_' + cleanLeadingDigits(f.originalName);
      f.aiUsed = false;
      batchInfo.ruleFallback++;
    }
  }
}

batchInfo.totalMs = Date.now() - t0;

// Phase 3：format final results + 唯一性檢查（避免覆蓋寫）
const seenNewNames = new Map();  // basePath → count

const results = [];
for (let i = 0; i < processed.length; i++) {
  const f = processed[i];
  if (!f.category) f.category = 'docs';
  if (!f.newName) f.newName = today + '_文件_' + cleanLeadingDigits(f.originalName);

  let newName = f.newName.replace(/[\\/:*?"<>|]/g, '_').substring(0, 100);
  if (!newName.match(/^\d{8}_/)) newName = today + '_' + newName;
  // 移除可能的副檔名（之後統一補回）
  newName = newName.replace(/\.[a-z0-9]{2,5}$/i, '');

  // 唯一性檢查：以 category+basename 為 key
  const key = f.category + '/' + newName;
  let finalName = newName;
  if (seenNewNames.has(key)) {
    const count = seenNewNames.get(key) + 1;
    seenNewNames.set(key, count);
    finalName = newName + '_' + count;
    batchInfo.dedupCount++;
  } else {
    seenNewNames.set(key, 1);
  }

  // 補回副檔名
  if (f.fileExt) finalName = finalName + '.' + f.fileExt;

  const out = {
    json: {
      originalName: f.originalName,
      category: f.category,
      newName: finalName,
      newPath: '/files/shared/client-organized/' + f.category + '/' + finalName,
      indexLine: '- **' + f.category + '** · ' + finalName + ' ← ' + f.originalName + (f.aiUsed ? '' : ' _(rule-based)_'),
      aiUsed: f.aiUsed,
      aiError: f.aiError
    },
    binary: f.binary
  };
  results.push(out);
}

batchInfo.outputCount = results.length;
if (results.length > 0) results[0].json._batchInfo = batchInfo;

return results;

const data = $input.first().json;
const lines = data.indexLine || [];
const cats = data.category || [];
const total = lines.length;
const counts = {};
for (const c of cats) counts[c] = (counts[c] || 0) + 1;

const today = new Date().toISOString().slice(0, 10);
const markdown = '# 客戶資料夾整理交接包 · ' + today + '\n\n' +
  '總共整理 ' + total + ' 份檔案。\n\n' +
  '## 分類統計\n' + Object.entries(counts).map(([k, v]) => '- ' + k + '：' + v + ' 份').join('\n') + '\n\n' +
  '## 檔案清單\n' + lines.join('\n') + '\n\n' +
  '---\n_自動產生於 ' + new Date().toLocaleString('zh-TW') + '_';

const tgMsg = '✅ 客戶資料夾整理完成\n\n' +
  '總計：' + total + ' 份\n' +
  Object.entries(counts).map(([k, v]) => k + '：' + v).join(' / ') + '\n\n' +
  '完整清單：shared/client-organized/_index.md';

return [{
  json: { tgMsg, indexPath: '/files/shared/client-organized/_index.md', total },
  binary: {
    data: {
      data: Buffer.from(markdown).toString('base64'),
      mimeType: 'text/markdown',
      fileName: '_index.md'
    }
  }
}];
